INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Zero-knowledge encrypted vault$q$, $q$Passwords, notes, and payment details are encrypted with XChaCha20 so that only the user, not Nord Security, can decrypt the data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Passkey support$q$, $q$Stores and autofills passkeys alongside traditional passwords for sites that support passwordless login.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Data Breach Scanner$q$, $q$Cross-references stored emails and passwords against known data breaches and alerts users to compromised credentials.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Password Health reports$q$, $q$Flags weak, reused, or old passwords across the vault and suggests stronger replacements.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Cross-platform autofill$q$, $q$Browser extensions and native apps for Windows, macOS, Linux, iOS, and Android autofill logins and forms automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Secure item sharing$q$, $q$Lets individuals and teams share specific passwords or items without exposing the full vault.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Admin console for teams$q$, $q$Business and Enterprise plans include centralized user management, activity logs, and permission groups.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Biometric unlock$q$, $q$Supports Face ID, Touch ID, and Windows Hello for quick, secure vault access on supported devices.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Lower price than most major competitors, especially on multi-year plans$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Zero-knowledge architecture backed by an established cybersecurity company$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Native passkey support ahead of many rivals$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Clean, easy-to-use interface across desktop, mobile, and browser extensions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Business and Enterprise tiers include SSO and provisioning for compliance needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Free plan restricts vault access to a single device at a time$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Fewer third-party integrations than 1Password or Keeper$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Multi-year billing required to reach the lowest advertised prices$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Company's Panama and Nord Security corporate structure draws occasional scrutiny from privacy researchers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Advanced features like emergency access are less mature than some competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Is NordPass free to use?$q$, $q$Yes, NordPass has a permanent free plan with unlimited password storage, though it limits vault access to one device at a time.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Who owns NordPass?$q$, $q$NordPass is developed by Nord Security, the cybersecurity company that also created NordVPN and NordLocker.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Does NordPass support passkeys?$q$, $q$Yes, NordPass can store and autofill passkeys in addition to traditional username and password credentials.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$How does NordPass encrypt data?$q$, $q$NordPass uses XChaCha20 encryption with a zero-knowledge model, so passwords are encrypted and decrypted locally on the user's device.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Can I share passwords with family or team members?$q$, $q$Yes, the Family plan supports up to 6 users with shared folders, and Business and Enterprise plans support item and folder sharing with granular permissions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$What platforms does NordPass support?$q$, $q$NordPass has apps for Windows, macOS, Linux, iOS, and Android, plus browser extensions for Chrome, Firefox, Edge, Safari, and Brave.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$How does NordPass compare to 1Password?$q$, $q$NordPass is generally cheaper and has native passkey support, while 1Password offers more mature third-party integrations and a longer enterprise track record.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Individual password management$q$, $q$A single user consolidates all logins, payment cards, and secure notes into one encrypted, autofill-enabled vault.$q$, $q$Individual consumers and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Family credential sharing$q$, $q$Families share select logins such as streaming services or shared bills across up to 6 accounts through the Family plan.$q$, $q$Households and families$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Small business credential governance$q$, $q$Growing teams centralize shared logins, enforce password health policies, and gain visibility into who accessed what through admin logs.$q$, $q$Small and mid-sized business IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, NULL, $q$["Unlimited password storage","One device at a time","Basic autofill"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Premium$q$, $q$$1.38-$1.99/month$q$, $q$1-year or 2-year billing$q$, NULL, $q$["Unlimited devices","Password Health reports","Data Breach Scanner","Passkey support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Family$q$, $q$$2.58-$3.69/month$q$, $q$1-year or 2-year billing$q$, NULL, $q$["Up to 6 Premium accounts","Shared folders","Individual encrypted vaults"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Teams$q$, $q$From $1.79-$2.49/user/month$q$, $q$Monthly, 1-year, or 2-year billing$q$, NULL, $q$["Shared team vaults","Basic admin controls","Up to 10 seats"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Business$q$, $q$From $2.87-$5.99/user/month$q$, $q$Monthly, 1-year, or 2-year billing$q$, NULL, $q$["Unlimited seats","Admin dashboard","Activity logs","Permission groups"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Enterprise$q$, $q$From $5.39/user/month (2-year)$q$, $q$Custom, typically annual or biennial$q$, NULL, $q$["SSO and SCIM provisioning","Advanced security policies","Dedicated account management"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NordPass is a password manager built by Nord Security, the company behind NordVPN, and was released in 2017 to give consumers and businesses a simpler way to store and autofill credentials across devices. It stores passwords, passkeys, payment cards, and secure notes in an encrypted vault protected by a single master password.$q$, $q$The product is positioned as a lower-cost alternative to legacy password managers while still offering enterprise-grade features such as centralized admin dashboards, activity logs, and directory integrations for larger teams. It is available as a browser extension, desktop application, and mobile app across all major platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$NordPass's core vault uses XChaCha20 encryption and a zero-knowledge architecture, meaning even Nord Security cannot access stored passwords. The Password Health feature scans a user's vault for weak, reused, or old passwords and suggests fixes, while the Data Breach Scanner checks saved emails and passwords against known leak databases.$q$, $q$The app supports passkey storage and autofill, letting users log in to supporting sites without a password at all. For teams, NordPass Business and Enterprise add shared item groups, granular permission controls, activity logs, and SSO/SCIM provisioning for larger organizations that need compliance-ready credential management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NordPass offers a permanently free plan limited to one device at a time, with unlimited password storage. Paid personal plans are Premium (single user) and Family (up to 6 users), both discounted heavily on 2-year terms compared to monthly billing.$q$, $q$Business pricing is split into Teams (small groups), Business (growing companies), and Enterprise (custom, with SSO and advanced provisioning), each billed per user per month with steep discounts for annual and biennial commitments.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Global server network$q$, $q$Thousands of servers across 100-plus countries provide broad geographic coverage for bypassing geo-restrictions and reducing latency.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$NordLynx protocol$q$, $q$A proprietary implementation built on WireGuard that balances high connection speeds with strong encryption.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Threat Protection Pro$q$, $q$Blocks malicious websites, trackers, and ads at the network level, even when the VPN itself is disconnected.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Kill switch$q$, $q$Automatically cuts internet access if the VPN connection drops, preventing accidental data exposure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$RAM-only servers$q$, $q$Servers run entirely on volatile memory and wipe all data on every reboot, reducing the risk of data retention.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Specialty servers$q$, $q$Dedicated servers for P2P file sharing, Onion over VPN, and double VPN hops for added anonymity.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Multi-device support$q$, $q$A single subscription can typically be used on up to 10 devices at once across desktop, mobile, and router apps.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Independently audited no-logs policy$q$, $q$NordVPN's no-logs claims have undergone multiple third-party security audits to verify the company does not retain user activity data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Large, consistently fast global server network$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Strong track record of independent no-logs and security audits$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Higher tiers bundle real extra value (password manager, cloud storage)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Works reliably with major streaming platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Broad multi-platform and multi-device support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Cheapest advertised prices only apply on 2-year commitments$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Renewal pricing after the promotional term is significantly higher$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Some advanced features (identity insurance) are limited to select regions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Interface can feel cluttered once extra security modules are enabled$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Business-focused network needs are better served by the separate NordLayer product$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$When was NordVPN founded?$q$, $q$NordVPN was founded in 2012 by Tomas Okmanas and Eimantas Sabaliauskas, initially incubated within the startup accelerator Tesonet.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Where is NordVPN headquartered?$q$, $q$Nord Security, NordVPN's parent company, is headquartered in Panama, with additional offices in Lithuania, the UK, and the Netherlands.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$How much does NordVPN cost?$q$, $q$Pricing ranges from about $3.09/month for the Basic plan on a 2-year term up to roughly $25/month for the Prime plan billed monthly.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Is NordVPN different from NordPass?$q$, $q$Yes, NordVPN and NordPass are separate products both made by Nord Security; NordVPN is a virtual private network and NordPass is a password manager.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Does NordVPN keep logs of user activity?$q$, $q$NordVPN states it follows a strict no-logs policy, which has been verified through multiple independent third-party audits.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$How many devices can I use with one NordVPN subscription?$q$, $q$A single NordVPN subscription typically supports up to 10 devices connected simultaneously.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Can NordVPN unblock streaming services?$q$, $q$NordVPN maintains dedicated infrastructure optimized for accessing major streaming platforms, though reliability can vary by title and region.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Secure browsing on public Wi-Fi$q$, $q$Travelers and remote workers encrypt their connection when using airport, hotel, or cafe Wi-Fi networks.$q$, $q$Remote workers and travelers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Bypassing geographic content restrictions$q$, $q$Users connect to servers in other countries to access region-locked streaming libraries or websites.$q$, $q$Streaming and entertainment users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Privacy-focused everyday browsing$q$, $q$Privacy-conscious individuals mask their IP address and block trackers and ads across all their devices.$q$, $q$Privacy-conscious consumers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Basic$q$, $q$$3.09-$12.99/month$q$, $q$Monthly, 1-year, or 2-year billing$q$, NULL, $q$["Core VPN encryption","NordLynx protocol","Kill switch","Up to 10 devices"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Plus$q$, $q$From roughly $4-$14/month$q$, $q$Monthly, 1-year, or 2-year billing$q$, NULL, $q$["Everything in Basic","NordPass password manager","Threat Protection Pro","Data breach scanner"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Complete$q$, $q$From roughly $6-$18/month$q$, $q$Monthly, 1-year, or 2-year billing$q$, NULL, $q$["Everything in Plus","1TB encrypted cloud storage (NordLocker)"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$Prime$q$, $q$Up to $25.29/month$q$, $q$Monthly, 1-year, or 2-year billing$q$, NULL, $q$["Everything in Complete","Identity theft protection","Credit monitoring","Cyber insurance (select regions)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NordVPN launched in 2012 as the flagship product of what later became Nord Security, growing from a small Lithuanian startup into one of the most recognized VPN brands worldwide. It encrypts a device's internet connection and routes traffic through a global server network to hide the user's IP address and location.$q$, $q$Beyond core VPN functionality, NordVPN has expanded into a broader digital security suite, bundling a password manager, malware and ad blocking, encrypted cloud storage, and identity protection features into its higher pricing tiers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$NordVPN operates thousands of servers across 100-plus countries and uses its proprietary NordLynx protocol, built on WireGuard, for fast, secure connections. Threat Protection Pro blocks malicious sites, trackers, and ads even when the VPN is off, and a kill switch prevents data leaks if the VPN connection drops.$q$, $q$Specialty servers support P2P file sharing, Onion over VPN, and double-hop encryption for extra anonymity. Higher-tier plans add a bundled password manager, 1TB of encrypted cloud storage, and, in some regions, identity theft monitoring and insurance coverage.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b5e7fc6-540c-4a46-90c4-6e863ad1c70c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NordVPN sells four tiers, Basic, Plus, Complete, and Prime, each available on monthly, 1-year, or 2-year billing, with per-month pricing dropping significantly on longer commitments. A single subscription covers multiple devices simultaneously.$q$, $q$Basic covers core VPN access, Plus layers in the password manager and advanced threat protection, Complete adds encrypted cloud storage, and Prime is the full bundle with identity protection features for eligible markets.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Built-in CI/CD pipelines$q$, $q$Automatically builds and deploys from GitHub, GitLab, or Bitbucket commits without needing a separate CI tool.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Full-stack preview environments$q$, $q$Spins up ephemeral environments, including services, databases, and jobs, for every pull request.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Managed databases$q$, $q$Provisions and manages Postgres, MySQL, MongoDB, Redis, and other datastores directly on the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Kubernetes-native infrastructure$q$, $q$Runs on Kubernetes under the hood while exposing a simplified interface, and integrates with EKS, GKE, and AKS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$GPU workload support$q$, $q$Supports GPU-backed compute for AI, ML training, and inference workloads alongside standard application hosting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Bring-your-own-cloud (BYOC)$q$, $q$Can be deployed into a customer's own cloud account for data residency, compliance, or cost-control reasons.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Secrets management and RBAC$q$, $q$Provides centralized secrets storage, role-based access control, SSO, and audit logging for team environments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Job and cron scheduling$q$, $q$Runs one-off and scheduled batch jobs alongside long-running services within the same platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Combines CI/CD, hosting, and databases into a single platform, reducing tool sprawl$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Exposes real Kubernetes power without requiring deep Kubernetes expertise$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Preview environments simplify testing full-stack changes per pull request$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$BYOC support gives enterprises control over data residency and cloud spend$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$GPU support makes it viable for AI/ML workloads, not just web apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Usage-based pricing can be harder to predict than flat PaaS pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Smaller company size than larger cloud platform vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Steeper learning curve than minimal PaaS tools like Render or Railway$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Enterprise and BYOC pricing requires a custom sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Smaller ecosystem of third-party integrations and community plugins than established clouds$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$What is Northflank used for?$q$, $q$Northflank is a platform for deploying applications, databases, and background jobs on Kubernetes with built-in CI/CD and preview environments.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Is Northflank free to use?$q$, $q$Yes, Northflank offers a free Developer Sandbox plan for hobby and small-scale projects; production usage is billed on a pay-as-you-go basis.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Can Northflank run in my own cloud account?$q$, $q$Yes, Northflank supports bring-your-own-cloud (BYOC) deployments across AWS, GCP, Azure, and on-premises Kubernetes clusters.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$How is Northflank different from Heroku or Render?$q$, $q$Northflank exposes more of the underlying Kubernetes infrastructure (RBAC, autoscaling, GPU support) while still offering a simplified developer experience, compared to the more abstracted models of Heroku and Render.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Does Northflank support GPU workloads?$q$, $q$Yes, Northflank supports GPU-backed compute for AI and machine learning training and inference alongside standard application hosting.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$When was Northflank founded?$q$, $q$Northflank was founded in 2019 and is headquartered in London, United Kingdom.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Who are Northflank's main competitors?$q$, $q$Competitors include Heroku, Render, Railway, and Fly.io on the simpler PaaS side, and managed Kubernetes services like EKS, GKE, and AKS on the infrastructure side.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Self-service internal developer platform$q$, $q$Platform engineering teams give developers self-service deployment without managing raw Kubernetes clusters themselves.$q$, $q$Platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Automated pull request preview environments$q$, $q$Engineering teams review full-stack changes, including database state, in an isolated environment before merging.$q$, $q$Software engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$AI and ML workload hosting$q$, $q$Teams run GPU-backed training and inference jobs alongside their standard application infrastructure on one platform.$q$, $q$AI and machine learning teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Developer Sandbox$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Hobby-scale deployments","Limited compute resources","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Pay-as-you-go$q$, $q$Usage-based$q$, $q$Monthly, billed on consumption$q$, NULL, $q$["Production-grade compute, storage, and networking","CI/CD pipelines","Preview environments","Managed databases"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$Enterprise / BYOC$q$, $q$Custom$q$, $q$Custom contract$q$, NULL, $q$["Bring-your-own-cloud deployment","SSO and advanced RBAC","Dedicated support","Compliance and data residency controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Northflank, founded in 2019 and based in London, is a cloud-native application platform that lets development teams deploy applications, databases, and jobs onto Kubernetes without managing raw cluster infrastructure directly. It positions itself between simple PaaS tools and unmanaged Kubernetes.$q$, $q$The platform can run on Northflank's managed cloud or be deployed into a customer's own AWS, GCP, or Azure account, giving enterprises flexibility over data residency and infrastructure ownership while keeping the same self-service developer experience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Northflank bundles CI/CD pipelines that trigger from Git commits, full-stack preview environments that spin up automatically for every pull request, and managed databases into one control plane, removing the need to stitch together separate CI, hosting, and database tools.$q$, $q$For teams with heavier workloads, Northflank supports GPU-backed compute for AI and ML jobs, secrets management, role-based access control, SSO, and audit logging, giving it enterprise-readiness typically associated with larger platform engineering investments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c0b6aed-6aed-4600-980d-b05aa2cf0ccb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Northflank offers a free Developer Sandbox plan for hobby projects and small-scale testing. Beyond that, pricing is consumption-based, charging for compute, storage, and network usage as workloads scale.$q$, $q$Enterprise and BYOC (bring-your-own-cloud) deployments are priced on custom contracts, typically negotiated for organizations with high-scale workloads or specific compliance and data residency requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Real-time malware and ransomware protection$q$, $q$Continuously scans for viruses, ransomware, and spyware using signature-based and behavioral detection.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Built-in Secure VPN$q$, $q$Includes a no-log VPN bundled into every Norton 360 tier for encrypting internet traffic on public networks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Cloud backup$q$, $q$Backs up files to Norton's encrypted cloud storage as protection against ransomware and hardware failure, with capacity varying by plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Password Manager$q$, $q$Stores and autofills passwords and payment information across devices at no extra cost within 360 plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Dark web monitoring$q$, $q$Scans dark web sources for the user's personal information and alerts them if data appears in a breach.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Norton Genie AI scam assistant$q$, $q$An AI-powered assistant that helps users evaluate suspicious messages, links, and calls for scam risk.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Smart Firewall$q$, $q$Monitors network traffic to and from the device to block unauthorized access attempts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$LifeLock identity theft protection$q$, $q$On select US plans, monitors for identity theft and provides restoration support and insurance coverage up to policy limits.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Consistently strong malware detection rates in independent lab tests$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$All-in-one bundle covers antivirus, VPN, backup, and password management$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$LifeLock identity protection is a differentiator not matched by most antivirus competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Long-standing brand with decades of security research and threat intelligence$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Virus Protection Promise offers a money-back guarantee for malware removal failures$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Renewal prices increase substantially after the first promotional year$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Lower tiers exclude the VPN, backup, or multi-device coverage found in higher tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Can consume more system resources than lightweight competitors during scans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$LifeLock identity protection features are largely limited to US customers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Bundle pricing can be more expensive than assembling equivalent standalone tools separately$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$What is included in Norton 360?$q$, $q$Norton 360 bundles antivirus and ransomware protection, a Secure VPN, a password manager, cloud backup, a Smart Firewall, and dark web monitoring, with identity theft protection on select higher tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$How much does Norton 360 cost?$q$, $q$First-year promotional pricing typically ranges from about $29.99 to $199.99 depending on the tier and number of devices, with renewal prices rising significantly after the first term.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Who owns Norton 360?$q$, $q$Norton 360 is a product of Gen Digital, formed in 2022 from the merger of NortonLifeLock and Avast, with dual headquarters in Tempe, Arizona and Prague, Czech Republic.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Is Norton 360 different from Norton AntiVirus Plus?$q$, $q$Yes, Norton AntiVirus Plus is the entry-level standalone antivirus product, while Norton 360 tiers add a VPN, cloud backup, and additional features in a bundled subscription.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$How many devices does Norton 360 cover?$q$, $q$Coverage ranges from a single device on Norton 360 Standard up to 10 or more devices on Norton 360 Premium and LifeLock-inclusive tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Does Norton 360 include identity theft protection?$q$, $q$Identity theft protection through LifeLock is included on Norton 360 with LifeLock Select and Advantage plans, primarily available to US customers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$What are the main alternatives to Norton 360?$q$, $q$Common alternatives include Bitdefender Total Security, McAfee Total Protection, Kaspersky Premium, and Malwarebytes.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$All-in-one home device protection$q$, $q$A household protects multiple PCs, Macs, and mobile devices with one subscription covering antivirus, VPN, and backup.$q$, $q$Home users and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Identity theft monitoring for US consumers$q$, $q$Individuals concerned about identity theft add LifeLock monitoring and restoration support alongside standard antivirus protection.$q$, $q$US-based consumers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Secure browsing on shared or public networks$q$, $q$Remote workers and travelers use the bundled Secure VPN to encrypt traffic when connecting to unfamiliar Wi-Fi networks.$q$, $q$Remote workers and frequent travelers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Norton AntiVirus Plus$q$, $q$~$5/device/month (annualized)$q$, $q$Annual$q$, NULL, $q$["Real-time antivirus","Smart Firewall","Password manager","2GB cloud backup"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Norton 360 Standard$q$, $q$From $29.99 first year$q$, $q$Annual$q$, NULL, $q$["1 device","Secure VPN","10GB cloud backup","Dark web monitoring"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Norton 360 Deluxe$q$, $q$From $49.99 first year$q$, $q$Annual$q$, NULL, $q$["Up to 5 devices","Secure VPN","50GB cloud backup","Parental controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Norton 360 Premium$q$, $q$From $99.99 first year$q$, $q$Annual$q$, NULL, $q$["Up to 10 devices","Secure VPN","75-100GB cloud backup","Dark web monitoring"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$Norton 360 with LifeLock Select/Advantage$q$, $q$From roughly $99.99-$199.99 first year$q$, $q$Annual$q$, NULL, $q$["Everything in Premium","Identity theft monitoring","Credit monitoring","Identity restoration support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Norton 360 is the bundled consumer security suite from Gen Digital, the parent company formed by the 2022 merger of NortonLifeLock and Avast. The Norton brand dates back to 1982, and the '360' naming was introduced in 2007 to signal all-around protection beyond basic antivirus.$q$, $q$Rather than selling antivirus alone, Norton 360 combines malware protection with a VPN, password manager, cloud backup, and, on higher tiers, identity theft protection through LifeLock, positioning it as an all-in-one digital security subscription for consumers and families.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core protection includes real-time antivirus and ransomware defense, a Smart Firewall, and Norton's Secure VPN built into every 360 tier. Cloud backup capacity scales from a few gigabytes on entry plans up to 100GB on Norton 360 Premium, protecting files against ransomware and hardware failure.$q$, $q$Gen Digital has layered in AI-driven scam detection through Norton Genie and broader Scam Protection features that help users identify phishing attempts, fake texts, and deepfake-based scams, alongside dark web monitoring that alerts users if their personal data appears in a breach.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0ef73c08-fc86-4679-b6fc-4e32b1333482', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Norton sells five main consumer tiers, from Norton AntiVirus Plus up to Norton 360 with LifeLock Select or Advantage, priced per year and scaled by number of covered devices and cloud backup capacity.$q$, $q$First-year promotional pricing is significantly lower than renewal pricing, with renewal rates often increasing by 50 to 140 percent after the first term, so buyers should check the auto-renewal price before subscribing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Calendar-centric note organization$q$, $q$Daily, weekly, monthly, and yearly notes form the primary structure for planning and journaling, rather than folders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Inline Markdown task management$q$, $q$Tasks are written directly in notes using Markdown syntax and can be scheduled, rescheduled, or moved between days.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Native Calendar and Reminders sync$q$, $q$Integrates with Apple's Calendar and Reminders apps so scheduled tasks and events appear in one unified view.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Local, plain-text Markdown storage$q$, $q$Notes are stored as Markdown files on-device with iCloud sync, avoiding lock-in to a proprietary data format.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Templates$q$, $q$Reusable templates speed up recurring note types such as meeting notes, daily planning pages, or project kickoffs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Backlinks and tags$q$, $q$Connects related notes through backlinks and hashtags, supporting personal knowledge management workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Plugins and scripting$q$, $q$A plugin system lets advanced users automate workflows and extend NotePlan's functionality.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Unique calendar-first organization bridges notes, tasks, and scheduling$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Local Markdown file storage gives users full data ownership$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Deep native integration with Apple Calendar and Reminders$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Flexible enough for GTD, time-blocking, and bullet-journal workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Lightweight, focused app built by an independent developer team$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Apple-only, with no native Windows, Android, or web app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$No permanent free plan, only a 7-day trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Smaller plugin and template ecosystem than Notion or Obsidian$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Steeper learning curve for users unfamiliar with Markdown syntax$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Small independent team means slower feature velocity than venture-backed competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$What platforms does NotePlan support?$q$, $q$NotePlan is available for macOS, iOS, and iPadOS; there is no native Windows, Android, or web version.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Is NotePlan free?$q$, $q$NotePlan offers a 7-day free trial, but ongoing use requires a Personal or Business subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$How does NotePlan store notes?$q$, $q$Notes are stored as local, plain-text Markdown files on the device, with optional iCloud sync across a user's Apple devices.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Does NotePlan sync with Apple Calendar?$q$, $q$Yes, NotePlan integrates with the native Apple Calendar and Reminders apps so scheduled tasks and events appear together.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Who created NotePlan?$q$, $q$NotePlan was created in 2016 by Berlin-based developer Eduard Metzger.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$How is NotePlan different from Notion or Obsidian?$q$, $q$NotePlan organizes notes and tasks around the calendar as the primary structure, whereas Notion uses databases and pages and Obsidian uses a folder-based note graph.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Can I use NotePlan for task management alone?$q$, $q$Yes, tasks can be created and scheduled without heavy note-taking, but NotePlan is designed to combine both in one workspace.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Daily time-blocked planning$q$, $q$Individuals plan their day by writing tasks directly into the daily note and scheduling them alongside calendar events.$q$, $q$Individual knowledge workers and planners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Markdown-based journaling$q$, $q$Writers and consultants keep a long-running journal of daily notes that stays searchable and linkable over time.$q$, $q$Writers, consultants, and journaling enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$GTD and project task tracking$q$, $q$Users following Getting Things Done or bullet-journal methods track project tasks across daily, weekly, and monthly notes.$q$, $q$Productivity method practitioners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Personal$q$, $q$$4.99/month$q$, $q$Monthly (7-day free trial)$q$, NULL, $q$["Full app access across Apple devices","iCloud sync","Templates and plugins","Calendar and Reminders integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$Business$q$, $q$$8.33/month$q$, $q$Monthly (7-day free trial)$q$, NULL, $q$["Everything in Personal","Business-tier licensing","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NotePlan was created in 2016 by Berlin-based developer Eduard Metzger to combine note-taking, task management, and calendar planning into one Markdown-based app for Apple devices. Rather than organizing notes into folders, NotePlan centers everything around daily, weekly, monthly, and yearly notes tied to the calendar.$q$, $q$The app stores all content as local, plain-text Markdown files, giving users full ownership of their data and the ability to edit notes in other Markdown editors if desired, while still offering iCloud sync across macOS, iOS, and iPadOS devices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Tasks are written inline within any note using Markdown checkbox syntax and can then be scheduled to specific calendar days, dragged between dates, or referenced across multiple notes. NotePlan syncs with the native Apple Calendar and Reminders apps, so time-blocked tasks and events appear alongside externally scheduled meetings.$q$, $q$Power users can extend NotePlan with templates for recurring note structures, backlinks and tags for connecting related notes, and a plugin and scripting system for automating repetitive workflows, giving it flexibility closer to Obsidian than to simpler calendar or to-do apps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b839ece-85d0-4b47-9358-2feed4175b10', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NotePlan is subscription-based with a Personal plan and a Business plan, both offering a 7-day free trial before billing begins. A subscription unlocks full functionality across all of a user's Apple devices.$q$, $q$There is no permanent free tier; access to core features requires an active subscription after the trial period ends.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Client-side end-to-end encryption$q$, $q$Notes are encrypted with XChaCha20-Poly1305 and Argon2 key derivation on-device before syncing, so the server never sees unencrypted content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Fully open-source codebase$q$, $q$Client apps and the sync server are both open source, letting anyone audit the code or self-host their own backend.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Notebooks and tags$q$, $q$Organizes notes into nested notebooks and tags for flexible categorization and retrieval.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Rich text editor with embeds$q$, $q$Supports formatted text, file attachments, and embedded content within notes on the Pro plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Secure note vault$q$, $q$Lets users lock individual sensitive notes behind an additional password or biometric check.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Cross-platform sync$q$, $q$Available on Windows, macOS, Linux, iOS, Android, and the web with encrypted sync across all devices.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Note version history$q$, $q$Pro plan retains historical versions of notes so users can restore earlier edits.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Fully open source, including the self-hostable sync server$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Strong zero-knowledge, client-side encryption model$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Affordable Pro pricing compared to many privacy-focused competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Feature-rich editor rather than a stripped-down 'private notes only' tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Available across all major desktop, mobile, and web platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Smaller company and team size than mainstream note-taking competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Free plan limits notebook count and lacks version history$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Smaller plugin and integration ecosystem than Evernote or Notion$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Self-hosting the sync server requires technical setup$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Less brand recognition outside privacy and open-source communities$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Is Notesnook really open source?$q$, $q$Yes, Notesnook is 100 percent open source, including both the client applications and the self-hostable sync server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$How does Notesnook encrypt notes?$q$, $q$Notesnook encrypts notes client-side using XChaCha20-Poly1305 for encryption and Argon2 for key derivation before any data is synced.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Is Notesnook free to use?$q$, $q$Yes, Notesnook has a free plan with core encrypted note-taking and sync; a Pro plan adds unlimited notebooks, version history, and vault protection.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Where is Notesnook based?$q$, $q$Notesnook is developed by Streetwriters (Private) Limited, a company based in Khushab, Pakistan, and was founded in 2019.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Can I self-host Notesnook?$q$, $q$Yes, because the sync server is open source, technically capable users can self-host their own backend instead of using Notesnook's hosted service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$How is Notesnook different from Evernote?$q$, $q$Notesnook is built around zero-knowledge end-to-end encryption and is fully open source, whereas Evernote does not offer end-to-end encryption or open-source transparency.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$What platforms does Notesnook support?$q$, $q$Notesnook has apps for Windows, macOS, Linux, iOS, Android, and a web app.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Private personal journaling$q$, $q$Individuals keep a daily journal or sensitive personal notes knowing that not even the provider can read the content.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Student and researcher note organization$q$, $q$Students organize class and research notes into notebooks and tags while keeping academic material encrypted and synced across devices.$q$, $q$Students and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Self-hosted encrypted notes$q$, $q$Technically capable users or small organizations self-host the open-source sync server for full control over where encrypted note data lives.$q$, $q$Open-source and self-hosting advocates$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, NULL, $q$["End-to-end encrypted notes","Basic notebooks and tags","Cross-platform sync","Limited notebook count"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$Pro$q$, $q$~$1.99-$8.99/month (roughly $4.49/month billed annually)$q$, $q$Monthly or annual billing$q$, NULL, $q$["Unlimited notebooks","Note version history","Rich embeds and attachments","Secure vault for locked notes"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Notesnook was founded in 2019 by Streetwriters, a small software company based in Khushab, Pakistan, to give privacy-conscious users a full-featured, end-to-end encrypted alternative to note apps like Evernote and OneNote.$q$, $q$The entire product, including client apps and the sync server, is open source, which lets technically inclined users audit the encryption implementation or self-host their own sync backend instead of relying on Notesnook's hosted infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Notes are encrypted client-side using XChaCha20-Poly1305 with Argon2 key derivation before syncing, so Notesnook's servers only ever store encrypted data, following a zero-knowledge model similar to privacy-first password managers.$q$, $q$Beyond encryption, Notesnook includes notebooks and nested organization, tags, rich text formatting with embeds and attachments, a locked vault for sensitive individual notes, and cross-platform apps for Windows, macOS, Linux, iOS, Android, and the web.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbef43e5-afc5-416f-a4bf-68df7c6a61ce', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Notesnook offers a free plan covering core encrypted note-taking, tagging, and sync across devices. The Pro plan unlocks unlimited notebooks, note version history, rich embeds, and vault protection, priced roughly between $1.99 and $8.99 per month depending on the billing term chosen.$q$, $q$As a bootstrapped, subscription-funded company, Notesnook relies on Pro subscriptions rather than venture funding or data monetization to sustain development.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Block-based editor$q$, $q$Every element, text, images, embeds, and databases, is a modular block that can be freely rearranged and nested within pages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Flexible databases$q$, $q$The same underlying data can be displayed as tables, boards, calendars, timelines, or galleries, adapting to different workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Notion AI and Notion Agent$q$, $q$Business and Enterprise plans include AI-assisted writing, summarization, and a multi-step Notion Agent that can complete tasks autonomously.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Team wikis and knowledge bases$q$, $q$Teams build searchable internal wikis with linked pages, permissions, and version history.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Templates and integrations$q$, $q$A large library of first-party and community templates, plus integrations with tools like Slack, Google Drive, and GitHub, speeds up setup.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Enterprise search$q$, $q$Business and Enterprise tiers can search across connected third-party apps directly from within Notion.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Guest and permission controls$q$, $q$Granular sharing settings let teams invite external collaborators or guests with scoped access to specific pages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Cross-platform availability$q$, $q$Available on web, Windows, macOS, iOS, and Android with real-time sync across devices.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Extremely flexible block-and-database model adapts to many different workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Can replace several single-purpose tools (wiki, docs, task tracker) in one workspace$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Large ecosystem of templates and community resources$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Increasingly capable AI features for summarization, search, and multi-step tasks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Generous free tier for individuals and students$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Full Notion AI functionality is now limited to Business and Enterprise plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Flexibility means more setup and configuration effort than opinionated tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Performance can slow down in very large, deeply nested workspaces$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Free plan caps file uploads and page history, limiting solo use over time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Enterprise pricing requires a custom sales conversation rather than transparent list pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Is Notion free to use?$q$, $q$Yes, Notion offers a free plan for individuals with unlimited blocks, though it caps guest invites, file upload size, and page history.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$How much does Notion cost for teams?$q$, $q$Notion Plus is $10 per user per month billed annually, and Notion Business is roughly $20 per user per month billed annually; Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Does Notion include AI features?$q$, $q$Yes, but full Notion AI access, including the Notion Agent and AI meeting notes, is now bundled exclusively into the Business and Enterprise plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Who founded Notion?$q$, $q$Notion was founded in 2013 by Ivan Zhao and Simon Last and is headquartered in San Francisco, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$What is Notion's valuation?$q$, $q$Notion reached an $11 billion valuation following a secondary tender offer in January 2026.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$What can Notion be used for?$q$, $q$Notion is commonly used for note-taking, team wikis, project and task management, documentation, and databases, often replacing several separate tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$What are the main alternatives to Notion?$q$, $q$Common alternatives include Confluence, Coda, ClickUp, Airtable, and Obsidian, depending on whether the primary use case is documentation, project management, or personal notes.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Team knowledge base and wiki$q$, $q$Companies build a searchable internal wiki for documentation, onboarding, and process guides accessible to the whole team.$q$, $q$Startups and growing companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Lightweight project management$q$, $q$Teams track tasks and projects using Notion's board and timeline database views instead of a dedicated project management tool.$q$, $q$Small to mid-sized product and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Personal notes and planning$q$, $q$Individuals use the free plan to organize personal notes, reading lists, and daily planning in one flexible workspace.$q$, $q$Students and individual users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Free$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Unlimited blocks for individuals","10 guest invites","5MB file upload cap","7-day page history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Plus$q$, $q$$10/user/month (annual) or $12/user/month (monthly)$q$, $q$Monthly or annual billing$q$, NULL, $q$["Unlimited file uploads","30-day version history","Unlimited guests","Limited Notion AI trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Business$q$, $q$~$20/user/month (annual)$q$, $q$Monthly or annual billing$q$, NULL, $q$["Full Notion AI access","Notion Agent","AI meeting notes","Enterprise search across connected apps"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$Enterprise$q$, $q$Custom$q$, $q$Custom contract$q$, NULL, $q$["SCIM provisioning","Audit logs","Unlimited page history","Advanced security controls","Dedicated customer success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Notion was founded in 2013 by Ivan Zhao and Simon Last and is headquartered in San Francisco, California. It has grown into one of the most widely used all-in-one workspace tools, combining notes, wikis, databases, and project tracking into a single flexible, block-based canvas.$q$, $q$The company has raised roughly $418 million in venture funding and reached an $11 billion valuation in a January 2026 secondary tender offer, with headcount growing to approximately 4,800 employees as it expands its enterprise and AI product lines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Notion's foundational concept is the block: every piece of content, from a paragraph to a database table, is a movable, nestable block that can be rearranged or linked to other pages, letting the same workspace serve as a personal notebook, team wiki, or project tracker.$q$, $q$Databases can be displayed as tables, boards, calendars, timelines, or galleries from the same underlying data, and Notion AI, available on Business and Enterprise plans, adds a multi-step Notion Agent, AI meeting notes, and enterprise search across connected third-party apps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f2cd50a-fcbc-4f86-9f47-5b2d1457d871', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Notion offers a permanently free plan for individuals with unlimited blocks but capped guest invites and file uploads. Plus, at $10/user/month billed annually, removes those caps and adds extended version history for small team collaboration.$q$, $q$Business, at roughly $20/user/month billed annually, unlocks full Notion AI functionality, while Enterprise adds SCIM provisioning, audit logs, and advanced security controls on a custom-priced contract requiring a sales conversation.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Fee-free business checking$q$, $q$No monthly fees, no minimum balance requirements, and no charges for incoming or outgoing ACH transfers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Novo Boost$q$, $q$Speeds up access to funds from integrated payment processors such as Stripe, reducing payout wait times.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Novo Reserves$q$, $q$Lets business owners create up to 10 sub-accounts to automatically set aside funds for taxes, payroll, or savings goals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Fee-free ATM access$q$, $q$Allows withdrawals at any ATM worldwide and refunds up to $7 per month in third-party ATM fees.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Accounting and e-commerce integrations$q$, $q$Connects with QuickBooks, Xero, Shopify, and Stripe to streamline bookkeeping and payment reconciliation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Free invoicing and bill pay$q$, $q$Includes free mobile check deposit, free bill pay with physical checks, and free bank checks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Mobile-first account management$q$, $q$A mobile app lets business owners manage transactions, reserves, and account settings on the go.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Genuinely free checking account with no monthly maintenance fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Novo Reserves make it easy to set aside funds for taxes or savings without a separate account$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Strong integrations with Stripe, Shopify, QuickBooks, and Xero for small business workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$No fees for ACH transfers, insufficient funds, or debit card replacement$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Modern, app-first user experience compared to traditional business banks$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Not a bank itself, deposits are held through a partner bank rather than Novo directly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$No interest-bearing checking or built-in high-yield savings option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Limited to a single core account type, less product breadth than some competitors like Mercury$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Outgoing domestic wire transfers carry a fee$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Customer support and dispute resolution can be slower than at larger traditional banks$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Is Novo a bank?$q$, $q$No, Novo is a fintech company, not a chartered bank; its checking accounts are provided through FDIC-insured partner banks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Does Novo charge monthly fees?$q$, $q$No, Novo's core business checking account has no monthly maintenance fees, no minimum balance requirements, and no ACH transfer fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$What is Novo Boost?$q$, $q$Novo Boost is a feature that speeds up access to funds from payment processors like Stripe, reducing payout wait times for businesses.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$What are Novo Reserves?$q$, $q$Novo Reserves let business owners create up to 10 sub-accounts within their Novo account to automatically set aside money for taxes, payroll, or other savings goals.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$When was Novo founded?$q$, $q$Novo was founded in 2016 by Michael Rangel, Tyler McIntyre, and Rijk Plasman and is headquartered in New York City.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Does Novo charge ATM fees?$q$, $q$Novo allows free withdrawals at any ATM worldwide and refunds up to $7 per month in third-party ATM fees charged by the ATM operator.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$What are the main alternatives to Novo?$q$, $q$Common alternatives include Mercury, Bluevine, Relay, and Found, as well as small business accounts from traditional banks like Chase and Bank of America.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Freelancer and solo entrepreneur banking$q$, $q$Independent contractors and freelancers separate personal and business finances with a free, no-minimum checking account.$q$, $q$Freelancers and solo entrepreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$E-commerce payout management$q$, $q$Online sellers use Novo Boost to get faster access to Stripe and Shopify payouts and track cash flow in real time.$q$, $q$E-commerce business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Small business budgeting with sub-accounts$q$, $q$Small business owners use Novo Reserves to automatically set aside funds for taxes, payroll, or growth goals without opening separate bank accounts.$q$, $q$Small business owners and startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$Novo Business Checking$q$, $q$Free$q$, $q$No monthly fee$q$, NULL, $q$["No minimum balance","No ACH transfer fees","Free mobile check deposit","Up to 10 Novo Reserves sub-accounts","Fee-free ATM withdrawals worldwide"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Novo was founded in 2016 by Michael Rangel, Tyler McIntyre, and Rijk Plasman and is headquartered in New York City. It provides free business checking accounts for small businesses, freelancers, and startups through FDIC-insured partner banks, operating as a fintech rather than a chartered bank itself.$q$, $q$The company has raised close to $300 million across multiple funding rounds through a Series C in 2023, and has grown to roughly 400 employees while focusing on serving solo entrepreneurs and small businesses that traditional banks often underserve.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Novo's core checking account carries no monthly fees, no minimum balance requirement, and no charges for incoming or outgoing ACH transfers, insufficient funds, or debit card replacement. It also refunds third-party ATM fees up to $7 per month and allows free withdrawals at any ATM worldwide.$q$, $q$Novo Boost speeds up access to funds from payment processors like Stripe, while Novo Reserves let business owners create up to 10 sub-accounts to automatically set aside money for taxes, payroll, or savings goals. Deep integrations with QuickBooks, Xero, Shopify, and Stripe streamline bookkeeping and payment workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('596a21e4-5cc6-4e45-bc09-c76587b5f3a1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Novo's core business checking account is entirely free, with no monthly maintenance fees or minimum balance requirements. The company generates revenue primarily through debit card interchange fees rather than charging users directly for the account itself.$q$, $q$Certain services, such as outgoing domestic wire transfers (typically $25-$30) and expedited card shipping, carry a fee, but the vast majority of everyday banking activity remains free.$q$]::text[], 2);
