-- ── NotePlan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$NotePlan is a Markdown-based notes, tasks, and calendar app for macOS, iOS, and iPadOS that unifies daily planning, task management, and note-taking in a single time-based workspace.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$4.99/month (Personal plan), 7-day free trial$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$NotePlan Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$NotePlan review 2026: how this Markdown notes, tasks, and calendar app works, pricing plans, and how it compares to Notion, Obsidian, and Todoist.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$NotePlan is a productivity app created in 2016 by developer Eduard Metzger in Berlin, Germany, that merges note-taking, task management, and calendar planning into a single Markdown-based workspace for Apple platforms (macOS, iOS, and iPadOS). Its core concept is time-based note organization: instead of storing notes in an arbitrary folder tree, NotePlan centers the experience around daily, weekly, monthly, quarterly, and yearly notes, letting users write journal entries, plan tasks, and reference project notes all within the flow of a calendar-driven structure. Tasks can be typed directly into any note using Markdown syntax and then scheduled onto specific days, dragged between dates, or synced with the device's native Calendar and Reminders apps, which distinguishes it from calendar-agnostic tools like Obsidian or task-only tools like Todoist. All notes are stored as plain-text Markdown files on the user's device (with optional iCloud or CloudKit sync across devices), giving users full data ownership and future-proofing rather than lock-in to a proprietary database format, a positioning similar to Obsidian's local-first philosophy but with tighter native calendar integration. NotePlan supports templates, backlinks, tags, and a plugin/scripting system for power users who want to automate recurring workflows, and it has built a loyal niche following among the productivity and personal-knowledge-management (PKM) community, particularly users of the Getting Things Done (GTD), time-blocking, and bullet-journal methodologies. As a small, independently run software company (a solo-founder to small-team operation, in contrast to venture-backed competitors), NotePlan operates on a straightforward subscription model with a Personal plan and a Business plan, both offering a 7-day free trial and full feature access across a user's devices once subscribed. Its target audience is individual knowledge workers, consultants, writers, and planners who want the flexibility of Markdown notes without giving up dedicated calendar and task-scheduling functionality. Primary competitors include Notion, Obsidian, Craft, Things 3, and Todoist, though NotePlan differentiates itself by being the rare tool that treats the calendar, not a folder or database, as the primary organizing structure for both notes and tasks.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b839ece-85d0-4b47-9358-2feed4175b10';

